import React from "react";

function Projects() {
  const projects = [
    {
      title: "Harare Southlands Slum Restructuring",
      description: "A visionary modular housing project blending technical, branding, and spiritual overlays for communal, government, and investor presentation.",
      image: "/logo.png" // placeholder, can replace with project-specific image
    },
    {
      title: "River Rehabilitation Initiative",
      description: "Comprehensive production budgets and modular infrastructure healing for sustainable water management and investor decks.",
      image: "/logo.png"
    },
    {
      title: "Silver Mekasi Resources Expansion",
      description: "Heap leach gold recovery simulations, cost breakdowns, and dashboard-ready visuals for investor review.",
      image: "/logo.png"
    }
  ];

  return (
    <div style={{ padding: "40px" }}>
      <h1 style={{ textAlign: "center", color: "#004080", marginBottom: "30px" }}>
        Our Projects
      </h1>
      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
        gap: "20px"
      }}>
        {projects.map((project, index) => (
          <div key={index} style={{
            border: "1px solid #ccc",
            borderRadius: "8px",
            padding: "20px",
            backgroundColor: "#fafafa",
            textAlign: "center"
          }}>
            <img src={project.image} alt={project.title} style={{ height: "100px", marginBottom: "15px" }} />
            <h2 style={{ color: "#004080" }}>{project.title}</h2>
            <p style={{ color: "#555" }}>{project.description}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Projects;
